
import React, { PureComponent } from 'react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend } from 'recharts';


const StackedArea = ({data})=> {
  
    return (
      <div className='chart card p-3 my-3'>
      <ResponsiveContainer width="100%" height="100%">
        <AreaChart
          width={500}
          height={400}
          data={data}
          margin={{
            top: 10,
            right: 30,
            left: 0,
            bottom: 0,
          }}
        >
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis dataKey="name"  />
          <YAxis type="number" />
          <Tooltip formatter={(value) => new Intl.NumberFormat('en').format(value)}/>
          <Area type="monotone" dataKey="principle" stackId="1" stroke="#8884d8" fill="#8884d8" />
          <Area type="monotone" dataKey="interest" stackId="1" stroke="#82ca9d" fill="#82ca9d" />
          <Area type="monotone" dataKey="balance" stackId="1" stroke="#ffc658" fill="#ffc658" />
          <Legend />
        </AreaChart>
        
      </ResponsiveContainer>
      </div>
    );
  
}

export default StackedArea;