import './App.css';
import { useState, useEffect } from 'react';
import AreaRechartComponent from './components/area.rechart';
import StackedArea from './components/StackedArea';
import Header from './components/Header'
import Table from './components/Table'
import MortgageValues from './components/MortgageValues'
import MortgageData from './mortgageData';

const App = () => {
  const [data, setData] = useState([])

  useEffect(()=> {
    const myData = [{
        name: `Feb 2021`,
        principle: 4392,
        interest: 7957,
        balance: 250000
    }]
    for (let i=0; i<25; i++){
      myData.push({
        name: `Feb ${2021+i}`,
        principle: myData[i].principle + 100,
        interest: myData[i].interest + 100,
        balance: myData[i].balance - 10000
      })
    }
    setData(myData)
  }, [])

  return(
    <div className='app container p-2'>
      <Header />
      <StackedArea data={data}/>
      <MortgageValues />
      {/* <Table /> */}
      {/* <AreaRechartComponent data={data}/> */}

    </div>
  )
}

export default App;